mapper.select:
select s.shift_info, f.*,r.roadway,a.group_no,a.borehole_no,ROUND(a.borehole_length,2),ROUND(a.borehole_length,2) AS boreholelength, CONCAT(f.punching_paragraph1,"-",f.punching_paragraph2)AS punchingparagraph, ROUND((f.punching_paragraph2-f.punching_paragraph1),2) AS punchingparagraphlength from t_actual_flushing f LEFT JOIN t_actual_borehole a ON a.id= f.borehole_id LEFT JOIN t_roadway r ON a.roadway_id=r.id LEFT JOIN t_shiftinfo s ON f.shift_id=s.id where 1=1 AND r.id IN
#{item}
AND a.group_no IN
#{item}
AND a.borehole_no IN
#{item}
and f.date_flushing BETWEEN #{startDate} and #{endDate}

select r.roadway,b.group_no,b.borehole_no, count(a.borehole_id) AS boreholecount, round(sum((a.punching_paragraph2-a.punching_paragraph1)),2) AS punchingparagraphlength, SUM(a.actual_coal_amount_flushed) AS actualCoalAmountFlushed, SUM(df.designed_coal_amount_flush) AS designedcoalamountflushed, round(SUM(a.actual_coal_amount_flushed)/SUM(df.designed_coal_amount_flush)*100,2) AS completionRatioFlushedCoal from t_actual_flushing a LEFT JOIN t_actual_borehole b ON a.borehole_id =b.id LEFT JOIN t_roadway r ON b.roadway_id =r.id LEFT JOIN t_designed_borehole d ON CONCAT(b.roadway_id,b.group_no,b.borehole_no)=CONCAT(d.roadway_id,d.group_no,d.borehole_no) LEFT JOIN t_designed_flushing df ON d.id=df.borehole_id where 1=1 AND r.id IN
#{item}
AND b.group_no IN
#{item}
AND b.borehole_no IN
#{item}
and b.drilling_date BETWEEN #{startDate} and #{endDate}
group by r.roadway

select f.*,r.roadway,a.group_no,a.borehole_no,a.borehole_length,(f.punching_paragraph2-f.punching_paragraph1) AS
punchingparagraphlength
from t_actual_flushing f
LEFT JOIN t_actual_borehole a ON a.id= f.borehole_id
LEFT JOIN t_roadway r ON a.roadway_id=r.id
where 1=1
AND r.id IN

        #{item}


AND a.group_no IN

        #{item}


AND a.borehole_no IN

        #{item}



    and f.date_flushing BETWEEN #{startDate} and #{endDate}

select s.shift_info, f.*,r.roadway,a.group_no,a.borehole_no,ROUND(a.borehole_length,2),ROUND(a.borehole_length,2) AS boreholelength, CONCAT(f.punching_paragraph1,"-",f.punching_paragraph2)AS punchingparagraph, ROUND((f.punching_paragraph2-f.punching_paragraph1),2) AS punchingparagraphlength from t_actual_flushing f LEFT JOIN t_actual_borehole a ON a.id= f.borehole_id LEFT JOIN t_roadway r ON a.roadway_id=r.id LEFT JOIN t_shiftinfo s ON f.shift_id=s.id where 1=1 AND r.id IN
#{item}
AND a.group_no IN
#{item}
AND a.borehole_no IN
#{item}
and f.date_flushing BETWEEN #{startDate} and #{endDate}

select f.id,r.roadway,sh.shift_info,sh.id AS shift_id,a.group_no,f.borehole_id,a.borehole_no,a.bore_diameter,a.borehole_length,a.azimuth_angle,a.inclination_angle, f.date_flushing,f.time_begin_flushing,f.time_end_flushing,f.total_time_flushing,f.water_pressure_during_flushing,f.gas_CONC_before_flushing, f.gas_CONC_after_flushing,f.punching_paragraph1,f.punching_paragraph2,f.see_coal_case,f.see_rock_case,CONCAT(f.punching_paragraph1,'~', f.punching_paragraph2) AS punchingparagraph,ROUND(f.punching_paragraph2-f.punching_paragraph1,2) AS length,f.actual_coal_amount_flushed, f.completion_ratio_flushed_coal,f.reception_time,f.gas_change_during,f.exception_phenomena,f.person_construction,f.chargehand, f.person_checking,f.other_person,f.remark from t_actual_flushing f LEFT JOIN t_actual_borehole a ON f.borehole_id=a.Id LEFT JOIN t_roadway r ON r.id=a.roadway_id LEFT JOIN t_shiftinfo sh ON sh.id=f.shift_id where 1=1 AND r.id IN
#{item}
AND a.group_no IN
#{item}
AND a.borehole_no IN
#{item}
and f.reception_time BETWEEN #{startDate} and #{endDate}
